const body = $json.body || {};

return [{
  json: {
    titulo:    body.titulo    || 'Não informado',
    problema:  body.problema  || body.descricao || 'Não informado',
    descricao: body.descricao || '',
    user:      body.user      || '',
    parecer_id: body.parecer_id || '',
    total_encontrado: 0,
    jurisprudencias: []
  }
}];

var r = $input.first().json;
var txt = '';
if (r.text)    { txt = r.text; }
else if (r.output)                    { txt = r.output; }
else if (r.content && r.content[0])   { txt = r.content[0].text; }
else { txt = JSON.stringify(r); }

var s = txt.indexOf('{');
var e = txt.lastIndexOf('}');
var q = { termos: [], query_ilike: 'contrato', confidence: 0.5 };
if (s > -1 && e > s) {
  try { q = JSON.parse(txt.slice(s, e + 1)); } catch(err) {}
}

var wb = $('Normalizar Input').first().json;
return [{ json: {
  query_ilike: q.query_ilike || 'contrato',
  termos:      q.termos      || [],
  confidence:  q.confidence  || 0.5,
  domain:      q.domain      || '',
  titulo:      wb.titulo,
  problema:    wb.problema,
  descricao:   wb.descricao,
  user:        wb.user,
  parecer_id:  wb.parecer_id
}}];

var resultados = $input.all();
var queryNode = $('Formatar Query').first().json;

var contexto = '';
var totalEncontrado = 0;

if (resultados && resultados.length > 0) {
  var docs = resultados.map(function(r) { return r.json; }).slice(0, 8);
  totalEncontrado = docs.length;

  contexto = docs.map(function(doc, i) {
    var orgao    = doc.orgao    || '';
    var numero   = doc.numero   || '';
    var data     = doc.data_pub || '';
    var ementa   = doc.ementa   || '';
    var conteudo = doc.conteudo || '';
    var referencia = conteudo.slice(-300);
    return '[' + (i+1) + '] ' + numero + ' — ' + orgao + ' (' + data + ')\nEmenta: ' + ementa + '\nReferência: ' + referencia;
  }).join('\n\n---\n\n');
}

return [{
  json: {
    problema:              queryNode.problema,
    titulo:                queryNode.titulo,
    descricao:             queryNode.descricao,
    user:                  queryNode.user,
    parecer_id:            queryNode.parecer_id,
    termos_buscados:       queryNode.termos,
    domain:                queryNode.domain,
    confidence:            queryNode.confidence,
    total_encontrado:      totalEncontrado,
    contexto_jurisprudencia: contexto
  }
}];

var r = $input.first().json;
var parecer = '';
if (r.text)                          { parecer = r.text; }
else if (r.output)                   { parecer = r.output; }
else if (r.content && r.content[0])  { parecer = r.content[0].text; }
else { parecer = JSON.stringify(r); }
return [{ json: { output: parecer } }];
